import React from 'react';
import { Link } from 'react-router-dom';

function Home() {
  return (
    <div style={{
      width: '100%',
      display: 'flex',
      flexDirection: 'column',
      backgroundColor: '#fff',
      margin: 0,
      padding: 0
    }}>
      {/* Video Section */}
      <div style={{
        width: '100%',
        height: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        position: 'relative',
        overflow: 'hidden',
        backgroundColor: '#000',
        margin: 0,
        padding: 0,
        flexShrink: 0
      }}>
        {/* Video Background */}
        <video
          autoPlay
          muted
          loop
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            objectFit: 'fill',
            zIndex: 1
          }}
        >
          <source src="/HomepageVideo.mp4" type="video/mp4" />
        </video>

        {/* Dark overlay */}
        <div style={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100%',
          height: '100%',
          backgroundColor: 'rgba(0, 0, 0, 0.3)',
          zIndex: 2
        }} />

        {/* Text overlay - no background bar */}
        <div style={{
          position: 'absolute',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 3
        }}>
          {/* Season text */}
          <h1 style={{
            fontSize: '48px',
            fontFamily: 'Helvetica, Arial, sans-serif',
            fontWeight: '700',
            letterSpacing: '0.5px',
            color: '#fff',
            margin: '0 0 20px 0',
            textAlign: 'center'
          }}>
            SPRING 2026
          </h1>

          {/* Browse collection link */}
          <Link to="/spring-2026" style={{
            fontSize: '12px',
            fontFamily: 'Helvetica, Arial, sans-serif',
            fontWeight: '300',
            letterSpacing: '1px',
            color: '#fff',
            backgroundColor: 'transparent',
            border: 'none',
            textDecoration: 'none',
            cursor: 'pointer',
            transition: 'all 0.3s'
          }}>
            BROWSE COLLECTION
          </Link>
        </div>
      </div>

      {/* Images Section */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
        gap: '20px',
        padding: '40px 20px',
        backgroundColor: '#fff'
      }}>
        {/* Picture 1 */}
        <img
          src="/image1.jpg"
          alt="Collection 1"
          style={{
            width: '100%',
            height: '400px',
            objectFit: 'cover',
            borderRadius: '4px'
          }}
        />

        {/* Picture 2 */}
        <img
          src="/image2.jpg"
          alt="Collection 2"
          style={{
            width: '100%',
            height: '400px',
            objectFit: 'cover',
            borderRadius: '4px'
          }}
        />
      </div>
    </div>
  );
}

export default Home;
